// frontend/src/components/EmailsList.tsx
import React from 'react';
import { useEmails } from '../hooks/useEmails';
import { Card, CardContent, CardHeader, CardTitle } from './ui/card';
import { Mail } from 'lucide-react';
import { Button } from './ui/button';

interface EmailsListProps {
  maxResults?: number;
  q?: string;
}

const EmailsList: React.FC<EmailsListProps> = ({ maxResults = 10, q }) => {
  const { loading, emails, error } = useEmails(maxResults, q);

  if (loading) return <div className="p-4">Loading emails...</div>;
  if (error) return <div className="p-4 text-red-600">{error}</div>;
  if (!emails.length) return <div className="p-4">No emails found</div>;

  return (
    <div className="space-y-3">
      {emails.map((m: any) => (
        <Card key={m.id}>
          <CardHeader>
            <CardTitle className="flex items-center">
              <Mail className="mr-2 h-4 w-4" />
              {m.id}
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-sm text-gray-700">
              {/* For now we show message id; you can call /api/email/:id for snippet/headers */}
              Message ID: {m.id}
            </div>
            <div className="mt-2">
              <Button onClick={() => window.open(`/emails/${m.id}`, '_self')}>
                Open
              </Button>
            </div>
          </CardContent>
        </Card>
      ))}
    </div>
  );
};

export default EmailsList;
